class Solution {
public:
    int compress(vector<char>& chars) {
        int n = chars.size();
        int write = 0;
        for (int read = 0; read < n; read++) {
            int i = read;
            while (i + 1 < n && chars[i] == chars[i + 1]) i++;
            chars[write++] = chars[read];
            if (i != read) {
                for (char c : to_string(i - read + 1)) chars[write++] = c;
            }
        }
        return write;
    }
};
```

